{
  "name": "The Nation's Eyes",
  "description": "A premium news and editorial blog featuring deep social and political commentary. Includes a robust admin dashboard for post and comment management, and AI-powered article extraction."
}

export interface Post {
  id: string;
  title: string;
  excerpt: string;
  content: string;
  author: string;
  date: string;
  category: string;
  imageUrl: string;
  readTime: string;
  status: 'published' | 'draft';
}

export interface Comment {
  id: string;
  postId: string;
  authorName: string;
  authorEmail: string;
  content: string;
  date: string;
  isApproved: boolean;
}

export interface User {
  username: string;
  role: 'admin';
  isLoggedIn: boolean;
}

export enum Category {
  POLITICS = 'Politics',
  ECONOMY = 'Economy',
  SOCIETY = 'Society',
  EDITORIAL = 'Editorial',
  WORLD = 'World'
}

import { Post, Comment, User } from '../types';
import { INITIAL_POSTS } from '../constants';

const POSTS_KEY = 'nations_eyes_posts';
const COMMENTS_KEY = 'nations_eyes_comments';
const AUTH_KEY = 'nations_eyes_auth';

export const storageService = {
  getPosts: (): Post[] => {
    const data = localStorage.getItem(POSTS_KEY);
    if (!data) {
      localStorage.setItem(POSTS_KEY, JSON.stringify(INITIAL_POSTS));
      return INITIAL_POSTS;
    }
    return JSON.parse(data);
  },

  savePost: (post: Post) => {
    const posts = storageService.getPosts();
    const index = posts.findIndex(p => p.id === post.id);
    if (index > -1) {
      posts[index] = post;
    } else {
      posts.unshift(post);
    }
    localStorage.setItem(POSTS_KEY, JSON.stringify(posts));
  },

  deletePost: (id: string) => {
    const posts = storageService.getPosts().filter(p => p.id !== id);
    localStorage.setItem(POSTS_KEY, JSON.stringify(posts));
  },

  getComments: (): Comment[] => {
    const data = localStorage.getItem(COMMENTS_KEY);
    return data ? JSON.parse(data) : [];
  },

  addComment: (comment: Comment) => {
    const comments = storageService.getComments();
    comments.push(comment);
    localStorage.setItem(COMMENTS_KEY, JSON.stringify(comments));
  },

  updateCommentStatus: (id: string, isApproved: boolean) => {
    const comments = storageService.getComments();
    const index = comments.findIndex(c => c.id === id);
    if (index > -1) {
      comments[index].isApproved = isApproved;
      localStorage.setItem(COMMENTS_KEY, JSON.stringify(comments));
    }
  },

  deleteComment: (id: string) => {
    const comments = storageService.getComments().filter(c => c.id !== id);
    localStorage.setItem(COMMENTS_KEY, JSON.stringify(comments));
  },

  getAuth: (): User | null => {
    const data = localStorage.getItem(AUTH_KEY);
    return data ? JSON.parse(data) : null;
  },

  setAuth: (user: User | null) => {
    if (user) {
      localStorage.setItem(AUTH_KEY, JSON.stringify(user));
    } else {
      localStorage.removeItem(AUTH_KEY);
    }
  }
};

import { GoogleGenAI, Type } from "@google/genai";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const geminiService = {
  async analyzeArticle(rawText: string) {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: `Extract a journalistic blog post from this Facebook content. Provide a catchy headline, a short excerpt (max 30 words), and the cleaned-up editorial content. Ensure the tone is professional and insightful like Noel Chiagorom.

Raw Text: ${rawText}`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            title: { type: Type.STRING },
            excerpt: { type: Type.STRING },
            content: { type: Type.STRING },
            category: { type: Type.STRING, description: 'One of: Politics, Economy, Society, Editorial, World' },
            readTime: { type: Type.STRING, description: 'Estimated read time like "5 min"' }
          },
          required: ["title", "excerpt", "content", "category", "readTime"]
        }
      }
    });

    try {
      return JSON.parse(response.text.trim());
    } catch (e) {
      console.error("Failed to parse AI response", e);
      return null;
    }
  }
};

