import React, { useState, useEffect } from 'react';
import { Post, Category } from '../types';
import { storageService } from '../services/storageService';
import ArticleCard from '../components/ArticleCard';

const Home: React.FC = () => {
  const [posts, setPosts] = useState<Post[]>([]);
  const [filter, setFilter] = useState<string>('All');

  useEffect(() => {
    const allPosts = storageService.getPosts().filter(p => p.status === 'published');
    setPosts(allPosts);
  }, []);

  const filteredPosts = filter === 'All' 
    ? posts 
    : posts.filter(p => p.category === filter);

  return (
    <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-12">
      {/* Hero Post */}
      {filter === 'All' && posts.length > 0 && (
        <ArticleCard post={posts[0]} isHero={true} />
      )}

      {/* Category Filter */}
      <div className="flex flex-wrap items-center gap-4 mb-12 border-b border-slate-200 pb-6 overflow-x-auto no-scrollbar">
        {['All', ...Object.values(Category)].map(cat => (
          <button
            key={cat}
            onClick={() => setFilter(cat)}
            className={`px-4 py-1.5 rounded-full text-sm font-medium transition-all ${
              filter === cat 
                ? 'bg-red-600 text-white' 
                : 'bg-white text-slate-600 hover:bg-slate-100 border border-slate-200'
            }`}
          >
            {cat}
          </button>
        ))}
      </div>

      {/* Grid */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
        {filteredPosts.slice(filter === 'All' ? 1 : 0).map(post => (
          <ArticleCard key={post.id} post={post} />
        ))}
      </div>

      {filteredPosts.length === 0 && (
        <div className="text-center py-20 bg-white rounded-xl shadow-sm border border-slate-200">
          <i className="fas fa-newspaper text-5xl text-slate-300 mb-4"></i>
          <h3 className="text-xl font-bold text-slate-600">No articles found in this category.</h3>
        </div>
      )}
    </div>
  );
};

export default Home;

import React, { useState, useEffect } from 'react';
import { useParams, Link } from 'react-router-dom';
import { Post, Comment } from '../types';
import { storageService } from '../services/storageService';

const ArticleDetail: React.FC = () => {
  const { id } = useParams<{ id: string }>();
  const [post, setPost] = useState<Post | null>(null);
  const [comments, setComments] = useState<Comment[]>([]);
  const [newComment, setNewComment] = useState({ name: '', email: '', content: '' });
  const [submitted, setSubmitted] = useState(false);

  useEffect(() => {
    if (id) {
      const posts = storageService.getPosts();
      const foundPost = posts.find(p => p.id === id);
      if (foundPost) {
        setPost(foundPost);
        const allComments = storageService.getComments();
        setComments(allComments.filter(c => c.postId === id && c.isApproved));
      }
    }
    window.scrollTo(0, 0);
  }, [id]);

  const handleCommentSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!id) return;

    const comment: Comment = {
      id: Date.now().toString(),
      postId: id,
      authorName: newComment.name,
      authorEmail: newComment.email,
      content: newComment.content,
      date: new Date().toISOString(),
      isApproved: false // Awaiting moderation
    };

    storageService.addComment(comment);
    setNewComment({ name: '', email: '', content: '' });
    setSubmitted(true);
    setTimeout(() => setSubmitted(false), 5000);
  };

  if (!post) return <div className="p-20 text-center">Loading...</div>;

  return (
    <article className="max-w-4xl mx-auto px-4 sm:px-6 py-12">
      <header className="mb-10 text-center">
        <Link to="/" className="text-red-600 font-bold hover:underline mb-4 inline-block uppercase tracking-widest text-sm">
          {post.category}
        </Link>
        <h1 className="text-4xl md:text-6xl font-bold mb-8 leading-tight">{post.title}</h1>
        <div className="flex items-center justify-center space-x-4 text-slate-500 text-sm">
          <img src={`https://ui-avatars.com/api/?name=${post.author}&background=dc2626&color=fff`} className="w-10 h-10 rounded-full" alt={post.author} />
          <div className="text-left">
            <p className="font-bold text-slate-900">{post.author}</p>
            <p>{new Date(post.date).toLocaleDateString()} • {post.readTime} read</p>
          </div>
        </div>
      </header>

      <img src={post.imageUrl} className="w-full h-[500px] object-cover rounded-2xl mb-12 shadow-lg" alt={post.title} />

      <div className="prose prose-lg max-w-none text-slate-700 leading-relaxed mb-16">
        {post.content.split('\n').map((para, i) => (
          <p key={i} className="mb-6">{para}</p>
        ))}
      </div>

      <hr className="border-slate-200 mb-16" />

      {/* Comment Section */}
      <section className="bg-white p-8 rounded-2xl border border-slate-200 shadow-sm">
        <h3 className="text-2xl font-bold mb-8">Comments ({comments.length})</h3>

        <div className="space-y-8 mb-12">
          {comments.map(comment => (
            <div key={comment.id} className="border-b border-slate-100 pb-6 last:border-0">
              <div className="flex justify-between items-center mb-2">
                <span className="font-bold text-slate-900">{comment.authorName}</span>
                <span className="text-xs text-slate-400">{new Date(comment.date).toLocaleDateString()}</span>
              </div>
              <p className="text-slate-600">{comment.content}</p>
            </div>
          ))}
          {comments.length === 0 && <p className="text-slate-400 italic">No comments yet. Be the first to share your thoughts.</p>}
        </div>

        <form onSubmit={handleCommentSubmit} className="space-y-4 border-t border-slate-100 pt-8">
          <h4 className="text-lg font-bold">Leave a Comment</h4>
          {submitted && (
            <div className="p-4 bg-green-50 text-green-700 rounded-lg text-sm border border-green-200">
              Your comment has been submitted and is awaiting moderation.
            </div>
          )}
          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            <input 
              required
              type="text" 
              placeholder="Full Name" 
              value={newComment.name}
              onChange={e => setNewComment({...newComment, name: e.target.value})}
              className="p-3 border border-slate-200 rounded-lg focus:ring-2 focus:ring-red-500 outline-none" 
            />
            <input 
              required
              type="email" 
              placeholder="Email Address" 
              value={newComment.email}
              onChange={e => setNewComment({...newComment, email: e.target.value})}
              className="p-3 border border-slate-200 rounded-lg focus:ring-2 focus:ring-red-500 outline-none" 
            />
          </div>
          <textarea 
            required
            rows={4} 
            placeholder="Write your comment here..." 
            value={newComment.content}
            onChange={e => setNewComment({...newComment, content: e.target.value})}
            className="w-full p-3 border border-slate-200 rounded-lg focus:ring-2 focus:ring-red-500 outline-none"
          ></textarea>
          <button type="submit" className="bg-red-600 text-white px-8 py-3 rounded-lg font-bold hover:bg-red-700 transition-colors shadow-lg shadow-red-200">
            Post Comment
          </button>
        </form>
      </section>
    </article>
  );
};

export default ArticleDetail;

