    { name: 'Pending Moderation', value: comments.filter(c => !c.isApproved).length, icon: 'fa-clock', color: 'orange' },
    { name: 'Drafts', value: posts.filter(p => p.status === 'draft').length, icon: 'fa-file-pen', color: 'slate' },
