    <div className="flex-1 min-w-0">
      <h4 className="text-[13px] md:text-[15px] font-black leading-tight text-slate-900 group-hover:text-red-600 transition-colors line-clamp-3 mb-2 uppercase tracking-tight">
        {post.title}
