import React, { useState, useEffect, useRef } from 'react';
import { Post } from '../types';
import { Link } from 'react-router-dom';

interface HeroSliderProps {
  posts: Post[];
}

const GRID_SIZE = { rows: 6, cols: 10 };

const HeroSlider: React.FC<HeroSliderProps> = ({ posts }) => {
  const [currentIndex, setCurrentIndex] = useState(0);
  const [prevIndex, setPrevIndex] = useState(0);
  const [isTransitioning, setIsTransitioning] = useState(false);
  const timerRef = useRef<NodeJS.Timeout | null>(null);

  const startTimer = () => {
    if (timerRef.current) clearInterval(timerRef.current);
    timerRef.current = setInterval(() => {
      handleNext();
    }, 5000);
  };

  useEffect(() => {
    startTimer();
    return () => {
      if (timerRef.current) clearInterval(timerRef.current);
    };
  }, [currentIndex]);

  const handleNext = () => {
    if (isTransitioning) return;
    setIsTransitioning(true);
    setPrevIndex(currentIndex);
    setCurrentIndex((prev) => (prev + 1) % posts.length);

    // Reset transition state after animation completes
    setTimeout(() => {
      setIsTransitioning(false);
    }, 1200);
  };

  if (!posts.length) return null;

  const currentPost = posts[currentIndex];
  const prevPost = posts[prevIndex];

  return (
    <div className="relative w-full h-[45vh] md:h-[500px] overflow-hidden rounded-[1.5rem] md:rounded-[2.5rem] shadow-2xl mb-6 md:mb-16 bg-black group">
      {/* Background Layer (Previous Slide - stays underneath) */}
      <div className="absolute inset-0 z-0">
        <img 
          src={prevPost.imageUrl} 
          className="w-full h-full object-cover opacity-40 scale-105"
          alt=""
        />
      </div>

      {/* Fragmented Transition Layer (Current Slide) */}
      <div className="absolute inset-0 z-10 pointer-events-none">
        <div 
          className="grid w-full h-full"
          style={{ 
            gridTemplateColumns: `repeat(${GRID_SIZE.cols}, 1fr)`,
            gridTemplateRows: `repeat(${GRID_SIZE.rows}, 1fr)`
          }}
        >
          {Array.from({ length: GRID_SIZE.rows * GRID_SIZE.cols }).map((_, i) => {
            const row = Math.floor(i / GRID_SIZE.cols);
            const col = i % GRID_SIZE.cols;
            const delay = (row + col) * 40; // Diagonal wave effect

            return (
              <div 
                key={i}
                className="relative overflow-hidden transition-all duration-700 ease-in-out"
                style={{
                  backgroundImage: `url(${currentPost.imageUrl})`,
                  backgroundSize: `${GRID_SIZE.cols * 100}% ${GRID_SIZE.rows * 100}%`,
                  backgroundPosition: `${(col / (GRID_SIZE.cols - 1)) * 100}% ${(row / (GRID_SIZE.rows - 1)) * 100}%`,
                  opacity: isTransitioning ? 0 : 0.6,
                  transform: isTransitioning ? 'scale(0) rotate(15deg)' : 'scale(1) rotate(0deg)',
                  transitionDelay: `${isTransitioning ? 0 : delay}ms`,
                }}
              />
            );
          })}
        </div>
      </div>

      {/* Static Gradient Overlay */}
      <div className="absolute inset-0 bg-gradient-to-t from-black via-black/40 to-transparent z-20"></div>

      {/* Content Layer */}
      <div className="absolute inset-0 z-30 flex flex-col justify-end p-5 md:p-10">
        <div key={currentPost.id} className="max-w-5xl animate-in fade-in slide-in-from-bottom-6 duration-700">
          <span className="inline-block px-3 py-1 bg-red-600 text-white text-[8px] md:text-[10px] font-black uppercase tracking-[0.2em] rounded-full mb-2 md:mb-4 shadow-xl">
            {currentPost.category}
          </span>
          <Link to={`/post/${currentPost.id}`} className="block no-underline">
